import React, { useState } from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

const studentNav = [
  { section: 'Main', items: [
    { to: '/dashboard', icon: '🏠', label: 'Dashboard' },
    { to: '/courses', icon: '📚', label: 'My Courses' },
    { to: '/compiler', icon: '💻', label: 'Code Practice' },
    { to: '/problems', icon: '🧩', label: 'Problem Set', badge: 'NEW' },
  ]},
  { section: 'Assessments', items: [
    { to: '/assessments', icon: '📝', label: 'Assessments' },
    { to: '/college-test', icon: '🎯', label: 'College Test' },
    { to: '/leaderboard', icon: '🏆', label: 'Leaderboard' },
  ]},
];

const adminNav = [
  { section: 'Admin Panel', items: [
    { to: '/admin', icon: '📊', label: 'Overview', exact: true },
    { to: '/admin/courses', icon: '📚', label: 'Manage Courses' },
    { to: '/admin/questions', icon: '❓', label: 'Question Bank' },
    { to: '/admin/assessments', icon: '📋', label: 'Assessments' },
    { to: '/admin/tests', icon: '🏫', label: 'College Tests' },
    { to: '/admin/students', icon: '👥', label: 'Students' },
  ]},
];

const collegeNav = [
  { section: 'College Portal', items: [
    { to: '/college', icon: '🏫', label: 'Test Portal' },
  ]},
];

export default function AppLayout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const navConfig = user?.role === 'admin' ? adminNav : user?.role === 'college' ? collegeNav : studentNav;

  const handleLogout = () => { logout(); navigate('/login'); };

  return (
    <div style={{ display:'flex', height:'100vh' }}>
      {/* Sidebar */}
      <aside style={{ width:260, minWidth:260, background:'#111827', borderRight:'1px solid #1e2d45', display:'flex', flexDirection:'column', overflow:'hidden' }}>
        {/* Logo */}
        <div style={{ padding:'22px 20px', borderBottom:'1px solid #1e2d45' }}>
          <div style={{ fontFamily:'Syne,sans-serif', fontSize:22, fontWeight:800 }}>
            <span style={{ color:'#00d4ff' }}>Edu</span><span style={{ color:'#7c3aed' }}>Code</span>
          </div>
          <div style={{ marginTop:14, display:'flex', alignItems:'center', gap:10 }}>
            <div style={{ width:36, height:36, borderRadius:'50%', background:'linear-gradient(135deg,#7c3aed,#00d4ff)', display:'flex', alignItems:'center', justifyContent:'center', fontWeight:700, fontSize:14, color:'#fff' }}>
              {user?.name?.[0]?.toUpperCase()}
            </div>
            <div>
              <div style={{ fontSize:13, fontWeight:600 }}>{user?.name}</div>
              <div style={{ fontSize:11, color:'#64748b', textTransform:'capitalize' }}>{user?.role}</div>
            </div>
          </div>
        </div>

        {/* Nav */}
        <nav style={{ flex:1, overflowY:'auto', padding:'8px 0' }}>
          {navConfig.map(section => (
            <div key={section.section} style={{ padding:'12px 12px 4px' }}>
              <div style={{ fontSize:10, textTransform:'uppercase', letterSpacing:'0.1em', color:'#64748b', padding:'0 8px', marginBottom:4 }}>{section.section}</div>
              {section.items.map(item => (
                <NavLink
                  key={item.to}
                  to={item.to}
                  end={item.exact}
                  style={({ isActive }) => ({
                    display:'flex', alignItems:'center', gap:10, padding:'9px 12px',
                    borderRadius:10, textDecoration:'none', fontSize:13, fontWeight:500,
                    marginBottom:2, transition:'all .15s',
                    color: isActive ? '#00d4ff' : '#64748b',
                    background: isActive ? 'rgba(0,212,255,0.08)' : 'transparent',
                    borderLeft: isActive ? '3px solid #00d4ff' : '3px solid transparent',
                  })}
                >
                  <span style={{ fontSize:16, width:20, textAlign:'center' }}>{item.icon}</span>
                  <span style={{ flex:1 }}>{item.label}</span>
                  {item.badge && <span style={{ background:'#7c3aed', color:'#fff', fontSize:9, padding:'2px 6px', borderRadius:8, fontWeight:700 }}>{item.badge}</span>}
                </NavLink>
              ))}
            </div>
          ))}
        </nav>

        {/* Footer */}
        <div style={{ padding:16, borderTop:'1px solid #1e2d45' }}>
          {user?.college && <div style={{ fontSize:11, color:'#64748b', marginBottom:8 }}>🏫 {user.college}</div>}
          <div onClick={handleLogout} style={{ display:'flex', alignItems:'center', gap:8, color:'#ef4444', cursor:'pointer', fontSize:13, padding:8, borderRadius:8, transition:'background .15s' }}
            onMouseEnter={e=>e.currentTarget.style.background='rgba(239,68,68,0.1)'}
            onMouseLeave={e=>e.currentTarget.style.background='transparent'}>
            🚪 Logout
          </div>
        </div>
      </aside>

      {/* Main */}
      <main style={{ flex:1, overflowY:'auto', background:'#0a0e1a', display:'flex', flexDirection:'column' }}>
        <Outlet />
      </main>
    </div>
  );
}
